const body = $json.body || $json;
if (!body.provider || !body.input) throw new Error('provider + input required');
if (!body.input.allowanceNumber) throw new Error('input.allowanceNumber required');
return [{ json: {
  correlationId: `inv-voidallow-${Date.now()}-${Math.floor(Math.random()*1e6)}`,
  startedAt: new Date().toISOString(),
  provider: body.provider,
  input: body.input
}}];

const state = $('Stamp correlation').first().json;
const statusCode = Number($json.statusCode ?? 0);
const ok = statusCode >= 200 && statusCode < 300;
const respBody = $json.body ?? $json;
return [{ json: { ...state, statusCode, ok, response: respBody, appliedAt: new Date().toISOString() } }];
